css:
color-scheme: dark;
  --app-bg: #0a0d12;
  --app-surface: rgba(180, 200, 220, 0.03);
  --app-surface-hover: rgba(180, 200, 220, 0.05);
  --app-border: rgba(180, 200, 220, 0.07);
  --app-border-strong: rgba(180, 200, 220, 0.12);
  --app-text: #e8eef4;
  --app-text-muted: #84909c;
  --app-accent: #9db4c8;
  --app-accent-soft: rgba(157, 180, 200, 0.14);
  --app-accent-border: rgba(157, 180, 200, 0.28);
  --app-accent-nav: rgba(157, 180, 200, 0.1);
  --app-elevated: #10141a;
  --app-glow-1: rgba(140, 170, 200, 0.14);
  --app-glow-2: rgba(90, 120, 150, 0.1);
  --app-card-shadow: 0 20px 40px rgba(0, 0, 0, 0.52), inset 0 1px 0 rgba(200, 220, 240, 0.08), inset 0 -1px 0 rgba(0, 0, 0, 0.42);
  --app-sidebar-bg: radial-gradient(circle at 14% -3%, var(--app-glow-1), transparent 42%), radial-gradient(circle at 88% 106%, var(--app-glow-2), transparent 40%), var(--app-bg);
  --app-shell-bg: var(--app-sidebar-bg);
  --media-snake-1: rgba(100, 130, 160, 0.14);
  --media-snake-2: rgba(157, 180, 200, 0.55);
  --media-snake-3: rgba(220, 232, 244, 0.95);
  --media-snake-4: rgba(120, 150, 180, 0.7);
  --bg-primary: var(--app-bg);
  --bg-secondary: var(--app-elevated);
  --bg-elevated: #161b22;
  --bg-glass: rgba(12, 16, 20, 0.88);
  --text-primary: var(--app-text);
  --text-secondary: var(--app-text-muted);
  --text-tertiary: rgba(132, 144, 156, 0.72);
  --accent: var(--app-accent);
  --accent-blue: var(--app-accent);
  --focus-glow: rgba(157, 180, 200, 0.22);
